+/**
+ * Creates a value-based query filter. All dependencies must be data traits;
+ * tags and relations cannot provide values to the predicate.
+ */
+export function createPredicate<T extends Trait[]>(
+    dependencies: T,
+    predicate: (data: PredicateData<T>) => boolean
+): Predicate<T> {
+    for (const dependency of dependencies) {
+        if (isRelation(dependency) || dependency[$internal].type === 'tag') {
+            throw new Error('Predicate dependencies must be data traits, not tags or relations.');
+        }
+    }
+
+    const result = createModifier('predicate', predicateId++, dependencies) as Predicate<T>;
+    result.predicate = predicate;
+    return result;
+}
+
+export function isPredicate(modifier: Modifier): modifier is Predicate {
+    return modifier.type === 'predicate' || Boolean((modifier as Predicate).predicate);
+}
+
+/** Returns false when any dependency is absent. */
+export function matchesPredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const values: unknown[] = [];
+    const eid = getEntityId(entity);
+
+    for (const dependency of predicate.traits) {
+        if (!hasTrait(world, entity, dependency)) return false;
+        const instance = world[$internal].traitInstances[dependency.id]!;
+        values.push(dependency[$internal].get(eid, instance.store));
+    }
+
+    return predicate.predicate(values as never);
+}
